{"content":"1: package oci
2: 
3: import (
4: 	"bytes"
5: 	"context"
6: 	"encoding/json"
7: 	"errors"
8: 	"fmt"
9: 	"io"
10: 	"io/fs"
11: 	"os"
12: 	"path"
13: 	"path/filepath"
14: 	"strings"
15: 	"time"
16: 
17: 	"github.com/opencontainers/go-digest"
18: 	v1 "github.com/opencontainers/image-spec/specs-go/v1"
19: 	"go.flipt.io/flipt/internal/containers"
20: 	"go.flipt.io/flipt/internal/ext"
21: 	storagefs "go.flipt.io/flipt/internal/storage/fs"
22: 	"go.uber.org/zap"
23: 	"oras.land/oras-go/v2"
24: 	"oras.land/oras-go/v2/content"
25: 	"oras.land/oras-go/v2/content/memory"
26: 	"oras.land/oras-go/v2/content/oci"
27: 	"oras.land/oras-go/v2/errdef"
28: 	"oras.land/oras-go/v2/registry"
29: 	"oras.land/oras-go/v2/registry/remote"
30: 	"oras.land/oras-go/v2/registry/remote/auth"
31: 	"oras.land/oras-go/v2/registry/remote/retry"
32: )
33: 
34: const (
35: 	SchemeHTTP  = "http"
36: 	SchemeHTTPS = "https"
37: 	SchemeFlipt = "flipt"
38: )
39: 
40: type credentialFunc func(registry string) auth.CredentialFunc
41: 
42: // Store is a type which can retrieve Flipt feature files from a target repository and reference
43: // Repositories can be local (OCI layout directories on the filesystem) or a remote registry
44: type Store struct {
45: 	opts   StoreOptions
46: 	logger *zap.Logger
47: 	local  oras.Target
48: }
49: 
50: // NewStore constructs and configures an instance of *Store for the provided config
51: func NewStore(logger *zap.Logger, dir string, opts ...containers.Option[StoreOptions]) (*Store, error) {
52: 	store := &Store{
53: 		opts: StoreOptions{
54: 			bundleDir:       dir,
55: 			manifestVersion: oras.PackManifestVersion1_1,
56: 		},
57: 		logger: logger,
58: 		local:  memory.New(),
59: 	}
60: 
61: 	containers.ApplyAll(&store.opts, opts...)
62: 
63: 	return store, nil
64: }
65: 
66: type Reference struct {
67: 	registry.Reference
68: 	Scheme string
69: }
70: 
71: func ParseReference(repository string) (Reference, error) {
72: 	scheme, repository, match := strings.Cut(repository, "://")
73: 	// support empty scheme as remote and https
74: 	if !match {
75: 		repository = scheme
76: 		scheme = SchemeHTTPS
77: 	}
78: 
79: 	if !strings.Contains(repository, "/") {
80: 		repository = "local/" + repository
81: 		scheme = SchemeFlipt
82: 	}
83: 
84: 	ref, err := registry.ParseReference(repository)
85: 	if err != nil {
86: 		return Reference{}, err
87: 	}
88: 
89: 	switch scheme {
90: 	case SchemeHTTP, SchemeHTTPS:
91: 	case SchemeFlipt:
92: 		if ref.Registry != "local" {
93: 			return Reference{}, fmt.Errorf("unexpected local reference: %q", ref)
94: 		}
95: 	default:
96: 		return Reference{}, fmt.Errorf("unexpected repository scheme: %q should be one of [http|https|flipt]", scheme)
97: 	}
98: 
99: 	return Reference{
100: 		Reference: ref,
101: 		Scheme:    scheme,
102: 	}, nil
103: }
104: 
105: func (s *Store) getTarget(ref Reference) (oras.Target, error) {
106: 	switch ref.Scheme {
107: 	case SchemeHTTP, SchemeHTTPS:
108: 		remote, err := remote.NewRepository(fmt.Sprintf("%s/%s", ref.Registry, ref.Repository))
109: 		if err != nil {
110: 			return nil, err
111: 		}
112: 
113: 		remote.PlainHTTP = ref.Scheme == "http"
114: 
115: 		if s.opts.auth != nil {
116: 			remote.Client = &auth.Client{
117: 				Credential: s.opts.auth(ref.Registry),
118: 				Cache:      auth.DefaultCache,
119: 				Client:     retry.DefaultClient,
120: 			}
121: 		}
122: 
123: 		return remote, nil
124: 	case SchemeFlipt:
125: 		// build the store once to ensure it is valid
126: 		store, err := oci.New(path.Join(s.opts.bundleDir, ref.Repository))
127: 		if err != nil {
128: 			return nil, err
129: 		}
130: 
131: 		store.AutoSaveIndex = true
132: 
133: 		return store, nil
134: 	}
135: 
136: 	return nil, fmt.Errorf("unexpected repository scheme: %q should be one of [http|https|flipt]", ref.Scheme)
137: }
138: 
139: // FetchOptions configures a call to Fetch
140: type FetchOptions struct {
141: 	IfNoMatch digest.Digest
142: }
143: 
144: // FetchResponse contains any fetched files for the given tracked reference
145: // If Matched == true, then the supplied IfNoMatch digest matched and Files should be nil
146: type FetchResponse struct {
147: 	Digest  digest.Digest
148: 	Files   []fs.File
149: 	Matched bool
150: }
151: 
152: // IfNoMatch configures the call to Fetch to return early if the supplied
153: // digest matches the target manifest pointed at by the underlying reference
154: // This is a cache optimization to skip re-fetching resources if the contents
155: // has already been seen by the caller
156: func IfNoMatch(digest digest.Digest) containers.Option[FetchOptions] {
157: 	return func(fo *FetchOptions) {
158: 		fo.IfNoMatch = digest
159: 	}
160: }
161: 
162: // Fetch retrieves the associated files for the tracked repository and reference
163: // It can optionally be configured to skip fetching given the caller has a digest
164: // that matches the current reference target
165: func (s *Store) Fetch(ctx context.Context, ref Reference, opts ...containers.Option[FetchOptions]) (*FetchResponse, error) {
166: 	var options FetchOptions
167: 	containers.ApplyAll(&options, opts...)
168: 
169: 	store, err := s.getTarget(ref)
170: 	if err != nil {
171: 		return nil, err
172: 	}
173: 
174: 	desc, err := oras.Copy(ctx,
175: 		store,
176: 		ref.Reference.Reference,
177: 		s.local,
178: 		ref.Reference.Reference,
179: 		oras.DefaultCopyOptions)
180: 	if err != nil {
181: 		return nil, err
182: 	}
183: 
184: 	bytes, err := content.FetchAll(ctx, s.local, desc)
185: 	if err != nil {
186: 		return nil, err
187: 	}
188: 
189: 	var manifest v1.Manifest
190: 	if err = json.Unmarshal(bytes, &manifest); err != nil {
191: 		return nil, err
192: 	}
193: 
194: 	var d digest.Digest
195: 	{
196: 		// shadow manifest so that we can safely
197: 		// strip annotations before calculating
198: 		// the digest
199: 		manifest := manifest
200: 		manifest.Annotations = map[string]string{}
201: 		bytes, err := json.Marshal(&manifest)
202: 		if err != nil {
203: 			return nil, err
204: 		}
205: 
206: 		d = digest.FromBytes(bytes)
207: 		if d == options.IfNoMatch {
208: 			return &FetchResponse{Matched: true, Digest: d}, nil
209: 		}
210: 	}
211: 
212: 	files, err := s.fetchFiles(ctx, store, manifest)
213: 	if err != nil {
214: 		return nil, err
215: 	}
216: 
217: 	return &FetchResponse{Files: files, Digest: d}, nil
218: }
219: 
220: // fetchFiles retrieves the associated flipt feature content files from the content fetcher.
221: // It traverses the provided manifests and returns a slice of file instances with appropriate
222: // content type extensions.
223: func (s *Store) fetchFiles(ctx context.Context, store oras.ReadOnlyTarget, manifest v1.Manifest) ([]fs.File, error) {
224: 	var files []fs.File
225: 
226: 	created, err := time.Parse(time.RFC3339, manifest.Annotations[v1.AnnotationCreated])
227: 	if err != nil {
228: 		return nil, err
229: 	}
230: 
231: 	for _, layer := range manifest.Layers {
232: 		mediaType, encoding, err := getMediaTypeAndEncoding(layer)
233: 		if err != nil {
234: 			return nil, fmt.Errorf("layer %q: %w", layer.Digest, err)
235: 		}
236: 
237: 		if mediaType != MediaTypeFliptNamespace {
238: 			return nil, fmt.Errorf("layer %q: type %q: %w", layer.Digest, mediaType, ErrUnexpectedMediaType)
239: 		}
240: 
241: 		switch encoding {
242: 		case "", "json", "yaml", "yml":
243: 		default:
244: 			return nil, fmt.Errorf("layer %q: unexpected layer encoding: %q", layer.Digest, encoding)
245: 		}
246: 
247: 		rc, err := store.Fetch(ctx, layer)
248: 		if err != nil {
249: 			return nil, err
250: 		}
251: 
252: 		files = append(files, &File{
253: 			ReadCloser: rc,
254: 			info: FileInfo{
255: 				desc:     layer,
256: 				encoding: encoding,
257: 				mod:      created,
258: 			},
259: 		})
260: 	}
261: 
262: 	return files, nil
263: }
264: 
265: // Bundle is a record of an existing Flipt feature bundle
266: type Bundle struct {
267: 	Digest     digest.Digest
268: 	Repository string
269: 	Tag        string
270: 	CreatedAt  time.Time
271: }
272: 
273: // List returns a slice of bundles available on the host
274: func (s *Store) List(ctx context.Context) (bundles []Bundle, _ error) {
275: 	fi, err := os.Open(s.opts.bundleDir)
276: 	if err != nil {
277: 		return nil, err
278: 	}
279: 
280: 	defer fi.Close()
281: 
282: 	entries, err := fi.ReadDir(-1)
283: 	if err != nil {
284: 		return nil, err
285: 	}
286: 
287: 	for _, entry := range entries {
288: 		bytes, err := os.ReadFile(filepath.Join(s.opts.bundleDir, entry.Name(), v1.ImageIndexFile))
289: 		if err != nil {
290: 			if errors.Is(err, os.ErrNotExist) {
291: 				return nil, nil
292: 			}
293: 
294: 			return nil, err
295: 		}
296: 
297: 		var index v1.Index
298: 		if err := json.Unmarshal(bytes, &index); err != nil {
299: 			return nil, err
300: 		}
301: 
302: 		for _, manifest := range index.Manifests {
303: 			digest := manifest.Digest
304: 			path := filepath.Join(s.opts.bundleDir, entry.Name(), "blobs", digest.Algorithm().String(), digest.Hex())
305: 			bytes, err := os.ReadFile(path)
306: 			if err != nil {
307: 				return nil, err
308: 			}
309: 
310: 			var man v1.Manifest
311: 			if err := json.Unmarshal(bytes, &man); err != nil {
312: 				return nil, err
313: 			}
314: 
315: 			bundle := Bundle{
316: 				Digest:     manifest.Digest,
317: 				Repository: entry.Name(),
318: 				Tag:        manifest.Annotations[v1.AnnotationRefName],
319: 			}
320: 
321: 			bundle.CreatedAt, err = parseCreated(man.Annotations)
322: 			if err != nil {
323: 				return nil, err
324: 			}
325: 
326: 			bundles = append(bundles, bundle)
327: 		}
328: 	}
329: 
330: 	return
331: }
332: 
333: // Build bundles the target directory Flipt feature state into the target configured on the Store
334: // It returns a Bundle which contains metadata regarding the resulting bundle details
335: func (s *Store) Build(ctx context.Context, src fs.FS, ref Reference) (Bundle, error) {
336: 	store, err := s.getTarget(ref)
337: 	if err != nil {
338: 		return Bundle{}, err
339: 	}
340: 
341: 	layers, err := s.buildLayers(ctx, store, src)
342: 	if err != nil {
343: 		return Bundle{}, err
344: 	}
345: 
346: 	desc, err := oras.PackManifest(ctx, store, s.opts.manifestVersion, MediaTypeFliptFeatures, oras.PackManifestOptions{
347: 		ManifestAnnotations: map[string]string{},
348: 		Layers:              layers,
349: 	})
350: 	if err != nil {
351: 		return Bundle{}, err
352: 	}
353: 
354: 	if ref.Reference.Reference != "" {
355: 		if err := store.Tag(ctx, desc, ref.Reference.Reference); err != nil {
356: 			return Bundle{}, err
357: 		}
358: 	}
359: 
360: 	bundle := Bundle{
361: 		Digest:     desc.Digest,
362: 		Repository: ref.Repository,
363: 		Tag:        ref.Reference.Reference,
364: 	}
365: 
366: 	bundle.CreatedAt, err = parseCreated(desc.Annotations)
367: 	if err != nil {
368: 		return Bundle{}, err
369: 	}
370: 
371: 	return bundle, nil
372: }
373: 
374: func (s *Store) buildLayers(ctx context.Context, store oras.Target, src fs.FS) (layers []v1.Descriptor, _ error) {
375: 	if err := storagefs.WalkDocuments(s.logger, src, func(doc *ext.Document) error {
376: 		payload, err := json.Marshal(&doc)
377: 		if err != nil {
378: 			return err
379: 		}
380: 
381: 		desc := v1.Descriptor{
382: 			Digest:    digest.FromBytes(payload),
383: 			Size:      int64(len(payload)),
384: 			MediaType: MediaTypeFliptNamespace,
385: 			Annotations: map[string]string{
386: 				AnnotationFliptNamespace: doc.Namespace,
387: 			},
388: 		}
389: 
390: 		s.logger.Debug("adding layer", zap.String("digest", desc.Digest.Hex()), zap.String("namespace", doc.Namespace))
391: 
392: 		if err := store.Push(ctx, desc, bytes.NewReader(payload)); err != nil && !errors.Is(err, errdef.ErrAlreadyExists) {
393: 			return err
394: 		}
395: 
396: 		layers = append(layers, desc)
397: 		return nil
398: 	}); err != nil {
399: 		return nil, err
400: 	}
401: 	return layers, nil
402: }
403: 
404: func (s *Store) Copy(ctx context.Context, src, dst Reference) (Bundle, error) {
405: 	if src.Reference.Reference == "" {
406: 		return Bundle{}, fmt.Errorf("source bundle: %w", ErrReferenceRequired)
407: 	}
408: 
409: 	if dst.Reference.Reference == "" {
410: 		return Bundle{}, fmt.Errorf("destination bundle: %w", ErrReferenceRequired)
411: 	}
412: 
413: 	srcTarget, err := s.getTarget(src)
414: 	if err != nil {
415: 		return Bundle{}, err
416: 	}
417: 
418: 	dstTarget, err := s.getTarget(dst)
419: 	if err != nil {
420: 		return Bundle{}, err
421: 	}
422: 
423: 	desc, err := oras.Copy(
424: 		ctx,
425: 		srcTarget,
426: 		src.Reference.Reference,
427: 		dstTarget,
428: 		dst.Reference.Reference,
429: 		oras.DefaultCopyOptions)
430: 	if err != nil {
431: 		return Bundle{}, err
432: 	}
433: 
434: 	rd, err := dstTarget.Fetch(ctx, desc)
435: 	if err != nil {
436: 		return Bundle{}, err
437: 	}
438: 
439: 	var man v1.Manifest
440: 	if err := json.NewDecoder(rd).Decode(&man); err != nil {
441: 		return Bundle{}, err
442: 	}
443: 
444: 	bundle := Bundle{
445: 		Digest:     desc.Digest,
446: 		Repository: dst.Repository,
447: 		Tag:        dst.Reference.Reference,
448: 	}
449: 
450: 	bundle.CreatedAt, err = parseCreated(man.Annotations)
451: 	if err != nil {
452: 		return Bundle{}, err
453: 	}
454: 
455: 	return bundle, nil
456: }
457: 
458: func getMediaTypeAndEncoding(layer v1.Descriptor) (mediaType, encoding string, _ error) {
459: 	var ok bool
460: 	if mediaType = layer.MediaType; mediaType == "" {
461: 		return "", "", ErrMissingMediaType
462: 	}
463: 
464: 	if mediaType, encoding, ok = strings.Cut(mediaType, "+"); !ok {
465: 		encoding = "json"
466: 	}
467: 
468: 	return
469: }
470: 
471: // File is a wrapper around a flipt feature state files contents.
472: type File struct {
473: 	io.ReadCloser
474: 	info FileInfo
475: }
476: 
477: // Seek attempts to seek the embedded read-closer.
478: // If the embedded read closer implements seek, then it delegates
479: // to that instances implementation. Alternatively, it returns
480: // an error signifying that the File cannot be seeked.
481: func (f *File) Seek(offset int64, whence int) (int64, error) {
482: 	if seek, ok := f.ReadCloser.(io.Seeker); ok {
483: 		return seek.Seek(offset, whence)
484: 	}
485: 
486: 	return 0, errors.New("seeker cannot seek")
487: }
488: 
489: func (f *File) Stat() (fs.FileInfo, error) {
490: 	return &f.info, nil
491: }
492: 
493: // FileInfo describes a flipt features state file instance.
494: type FileInfo struct {
495: 	desc     v1.Descriptor
496: 	encoding string
497: 	mod      time.Time
498: }
499: 
500: func (f FileInfo) Name() string {
501: 	return f.desc.Digest.Hex() + "." + f.encoding
502: }
503: 
504: func (f FileInfo) Size() int64 {
505: 	return f.desc.Size
506: }
507: 
508: func (f FileInfo) Mode() fs.FileMode {
509: 	return fs.ModePerm
510: }
511: 
512: func (f FileInfo) ModTime() time.Time {
513: 	return f.mod
514: }
515: 
516: func (f FileInfo) IsDir() bool {
517: 	return false
518: }
519: 
520: func (f FileInfo) Sys() any {
521: 	return nil
522: }
523: 
524: func parseCreated(annotations map[string]string) (time.Time, error) {
525: 	return time.Parse(time.RFC3339, annotations[v1.AnnotationCreated])
