16: type bundleCommand struct{}
17: 
18: func newBundleCommand() *cobra.Command {
19: 	bundle := &bundleCommand{}
20: 
21: 	cmd := &cobra.Command{
22: 		Use:   "bundle",
23: 		Short: "Manage Flipt bundles",
24: 	}
25: 
26: 	cmd.AddCommand(&cobra.Command{
27: 		Use:   "build [flags] <name>",
28: 		Short: "Build a bundle",
29: 		RunE:  bundle.build,
30: 		Args:  cobra.ExactArgs(1),
31: 	})
32: 
33: 	cmd.AddCommand(&cobra.Command{
34: 		Use:   "list [flags]",
35: 		Short: "List all bundles",
36: 		RunE:  bundle.list,
37: 	})
38: 
39: 	cmd.AddCommand(&cobra.Command{
40: 		Use:   "push [flags] <from> <to>",
41: 		Short: "Push local bundle to remote",
42: 		RunE:  bundle.push,
43: 		Args:  cobra.ExactArgs(2),
44: 	})
45: 
46: 	cmd.AddCommand(&cobra.Command{
47: 		Use:   "pull [flags] <remote>",
48: 		Short: "Pull a remote bundle",
49: 		RunE:  bundle.pull,
50: 		Args:  cobra.ExactArgs(1),
51: 	})
52: 
53: 	return cmd
54: }
55: 
56: func (c *bundleCommand) build(cmd *cobra.Command, args []string) error {
57: 	store, err := c.getStore()
58: 	if err != nil {
59: 		return err
60: 	}
61: 
62: 	ref, err := oci.ParseReference(args[0])
63: 	if err != nil {
64: 		return err
65: 	}
66: 
67: 	bundle, err := store.Build(cmd.Context(), os.DirFS("."), ref)
68: 	if err != nil {
69: 		return err
70: 	}
71: 
72: 	fmt.Println(bundle.Digest)
73: 
74: 	return nil
75: }
76: 
77: func (c *bundleCommand) list(cmd *cobra.Command, args []string) error {
78: 	store, err := c.getStore()
79: 	if err != nil {
80: 		return err
81: 	}
82: 
83: 	bundles, err := store.List(cmd.Context())
84: 	if err != nil {
85: 		return err
86: 	}
87: 
88: 	wr := writer()
89: 
90: 	fmt.Fprintf(wr, "DIGEST\tREPO\tTAG\tCREATED\t\n")
91: 	for _, bundle := range bundles {
92: 		fmt.Fprintf(wr, "%s\t%s\t%s\t%s\t\n", bundle.Digest.Hex()[:7], bundle.Repository, bundle.Tag, bundle.CreatedAt)
93: 	}
94: 
95: 	return wr.Flush()
96: }
97: 
98: func (c *bundleCommand) push(cmd *cobra.Command, args []string) error {
99: 	store, err := c.getStore()
100: 	if err != nil {
101: 		return err
102: 	}
103: 
104: 	src, err := oci.ParseReference(args[0])
105: 	if err != nil {
106: 		return err
107: 	}
108: 
109: 	dst, err := oci.ParseReference(args[1])
110: 	if err != nil {
111: 		return err
112: 	}
113: 
114: 	bundle, err := store.Copy(cmd.Context(), src, dst)
115: 	if err != nil {
116: 		return err
117: 	}
118: 
119: 	fmt.Println(bundle.Digest)
120: 
121: 	return nil
122: }
123: 
124: func (c *bundleCommand) pull(cmd *cobra.Command, args []string) error {
125: 	store, err := c.getStore()
126: 	if err != nil {
127: 		return err
128: 	}
129: 
130: 	src, err := oci.ParseReference(args[0])
131: 	if err != nil {
132: 		return err
133: 	}
134: 
135: 	// copy source into destination and rewrite
136: 	// to reference the local equivalent name
137: 	dst := src
138: 	dst.Registry = "local"
139: 	dst.Scheme = "flipt"
140: 
141: 	bundle, err := store.Copy(cmd.Context(), src, dst)
142: 	if err != nil {
143: 		return err
144: 	}
145: 
146: 	fmt.Println(bundle.Digest)
147: 
148: 	return nil
149: }
150: 
151: func (c *bundleCommand) getStore() (*oci.Store, error) {
152: 	logger, cfg, err := buildConfig()
153: 	if err != nil {
154: 		return nil, err
155: 	}
156: 
157: 	dir, err := config.DefaultBundleDir()
158: 	if err != nil {
159: 		return nil, err
160: 	}
161: 
162: 	var opts []containers.Option[oci.StoreOptions]
163: 	if cfg := cfg.Storage.OCI; cfg != nil {
164: 		if cfg.Authentication != nil {
165: 			if !cfg.Authentication.Type.IsValid() {
166: 				cfg.Authentication.Type = oci.AuthenticationTypeStatic
167: 			}
168: 			opt, err := oci.WithCredentials(
169: 				cfg.Authentication.Type,
170: 				cfg.Authentication.Username,
171: 				cfg.Authentication.Password,
172: 			)
173: 			if err != nil {
174: 				return nil, err
175: 			}
176: 			opts = append(opts, opt)
177: 		}
178: 
179: 		// The default is the 1.1 version, this is why we don't need to check it in here.
180: 		if cfg.ManifestVersion == config.OCIManifestVersion10 {
181: 			opts = append(opts, oci.WithManifestVersion(oras.PackManifestVersion1_0))
182: 		}
183: 
184: 		if cfg.BundlesDirectory != "" {
185: 			dir = cfg.BundlesDirectory
186: 		}
187: 	}
188: 
189: 	return oci.NewStore(logger, dir, opts...)
190: }
191: 
192: func writer() *tabwriter.Writer {
193: 	return tabwriter.NewWriter(os.Stdout, 0, 0, 3, ' ', 0)
194: }
